UPDATE TEXTBOOK_INVENTORY
SET
    TOT_INVT_CNT   = #{totInvtCnt}
    , SALABLE_CNT  = #{salableCnt}
    , SALE_CMPL_CNT = #{saleCmplCnt, jdbcType=NUMERIC}
    , RSRV_WAIT_CNT = #{rsrvWaitCnt, jdbcType=NUMERIC}
    , DMGD_DSPSL_CNT = #{dmgdDspslCnt, jdbcType=NUMERIC}
    , MIN_KEEP_CNT = #{minKeepCnt, jdbcType=NUMERIC}
    , INVT_STAT_CD = #{invtStatCd, jdbcType=CHAR}
    , LAST_MDFR_ID = #{lastMdfrId}
    , MDFCN_DT     = CURRENT_TIMESTAMP
WHERE TEXTBOOK_SN = #{textbookSn}

sql.trim:
AND h.TEXTBOOK_SN = #{detailCondition.textbookSn}

    AND h.IO_TYPE_CD = #{detailCondition.ioTypeCd}


    AND h.PROC_DT >= TO_DATE(#{detailCondition.startDt}, 'YYYY-MM-DD')


    AND h.PROC_DT < TO_DATE(#{detailCondition.endDt}, 'YYYY-MM-DD') + 1


    AND instr(h.PROC_USER_ID, #{detailCondition.keyword}) > 0
